/*
 * Raspberry Pi Hardware Register Access (C)
 * This program demonstrates reading hardware information from
 * Raspberry Pi registers at the hardware level.
 * Note: Requires root privileges to access /dev/mem
 * 
 * Educational purpose: Understanding how software interacts
 * with hardware at the register level.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/mman.h>

/* Raspberry Pi Model Definitions */
#define RPI_PHYSICAL_OFFSET     0x20000000  /* Peripheral base address (Pi 1-3) */
#define RPI4_PHYSICAL_OFFSET   0xFE000000  /* Peripheral base address (Pi 4) */
#define PAGE_SIZE              4096
#define BLOCK_SIZE             PAGE_SIZE

/* Hardware Revision Register Bits */
#define RPI_HWVER_MASK         0x0000FFFF
#define RPI_HWVER_PI1          0x0000
#define RPI_HWVER_PI2          0x0004
#define RPI_HWVER_PI3          0x0008
#define RPI_HWVER_PI4          0x0011

/* Clock register addresses (relative to peripheral base) */
#define CLK_BASE_OFFSET        0x101000     /* Clock manager base */
#define CLK_GP0_CTL            0x101070     /* General purpose clock 0 */
#define CLK_GP0_DIV            0x101074     /* General purpose clock 0 divisor */

/* GPIO register offsets */
#define GPIO_BASE_OFFSET       0x200000     /* GPIO controller base */
#define GPIO_GPFSEL0           0x00         /* Function select register 0 */
#define GPIO_GPFSEL1           0x04         /* Function select register 1 */
#define GPIO_GPFSEL2           0x08         /* Function select register 2 */
#define GPIO_GPSET0            0x1C         /* Pin output set register 0 */
#define GPIO_GPCLR0            0x28         /* Pin output clear register 0 */
#define GPIO_GPLEV0            0x34         /* Pin level register 0 */

/* Structure to hold Raspberry Pi board information */
typedef struct {
    uint32_t hardware_id;
    uint32_t revision;
    char model[64];
    uint32_t peripheral_base;
    uint32_t memory_size;
} RPiHardwareInfo;

/*
 * Map memory region for hardware register access
 */
void *map_peripheral(uint32_t base, uint32_t len) {
    int fd;
    void *map;

    /* Open /dev/mem for physical memory access */
    fd = open("/dev/mem", O_RDONLY);
    if (fd < 0) {
        printf("Error: Cannot open /dev/mem. Run as root.\n");
        return NULL;
    }

    /* Map the memory region */
    map = mmap(NULL, len, PROT_READ, MAP_SHARED, fd, base);
    close(fd);

    if (map == MAP_FAILED) {
        printf("Error: Memory mapping failed.\n");
        return NULL;
    }

    return map;
}

/*
 * Determine Raspberry Pi model from hardware revision
 */
void identify_rpi_model(RPiHardwareInfo *info) {
    FILE *fp;
    char line[256];
    char *token;
    uint32_t revision = 0;

    /* Read from /proc/cpuinfo to get hardware revision */
    fp = fopen("/proc/cpuinfo", "r");
    if (fp == NULL) {
        strcpy(info->model, "Unknown");
        return;
    }

    while (fgets(line, sizeof(line), fp)) {
        if (strncmp(line, "Revision", 8) == 0) {
            token = strchr(line, ':');
            if (token) {
                sscanf(token + 1, "%x", &revision);
                info->revision = revision;
            }
        }
    }
    fclose(fp);

    /* Extract model from revision code */
    /* Bits 0-3: PCB revision, Bit 4: WKetly 5-7: Memory size, Bit 11: Manufacturer */
    uint8_t major_rev = (revision >> 4) & 0x0F;

    switch (major_rev) {
        case 0:
            strcpy(info->model, "Raspberry Pi Model B (256MB)");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 1:
            strcpy(info->model, "Raspberry Pi Model A");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 2:
            strcpy(info->model, "Raspberry Pi Model B (512MB)");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 3:
            strcpy(info->model, "Raspberry Pi Model B+");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 4:
            strcpy(info->model, "Raspberry Pi Compute Module");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 8:
            strcpy(info->model, "Raspberry Pi 2 Model B");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 9:
            strcpy(info->model, "Raspberry Pi 3 Model B");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
            break;
        case 17:
            strcpy(info->model, "Raspberry Pi 4 Model B");
            info->peripheral_base = RPI4_PHYSICAL_OFFSET;
            break;
        default:
            strcpy(info->model, "Raspberry Pi (Unknown revision)");
            info->peripheral_base = RPI_PHYSICAL_OFFSET;
    }

    /* Check for new revision scheme (over 0x1000) */
    if (revision >= 0x1000) {
        uint8_t encoding = (revision >> 23) & 0x1F;
        snprintf(info->model + strlen(info->model), 64, " - Encoding: %d", encoding);
    }
}

/*
 * Read memory information
 */
void get_memory_info(RPiHardwareInfo *info) {
    FILE *fp;
    char line[256];
    uint32_t mem_total_kb = 0;

    fp = fopen("/proc/meminfo", "r");
    if (fp == NULL) return;

    while (fgets(line, sizeof(line), fp)) {
        if (strncmp(line, "MemTotal:", 9) == 0) {
            sscanf(line + 9, "%u", &mem_total_kb);
            break;
        }
    }
    fclose(fp);

    info->memory_size = mem_total_kb * 1024;  /* Convert to bytes */
}

/*
 * Demonstrate GPIO register reading
 */
void read_gpio_registers(uint32_t peripheral_base) {
    volatile uint32_t *gpio_regs;
    uint32_t gpfsel0_value;

    printf("\n--- GPIO Register Sample ---\n");

    gpio_regs = (volatile uint32_t *)map_peripheral(
        peripheral_base + GPIO_BASE_OFFSET, 
        BLOCK_SIZE
    );

    if (gpio_regs == NULL) {
        printf("Cannot read GPIO registers (needs root)\n");
        return;
    }

    /* Read GPIO Function Select Register 0 (pins 0-9) */
    gpfsel0_value = gpio_regs[GPIO_GPFSEL0 / 4];
    printf("GPFSEL0 Register: 0x%08X\n", gpfsel0_value);
    printf("  Bits 0-2 (GPIO0): %u\n", gpfsel0_value & 0x7);
    printf("  Bits 3-5 (GPIO1): %u\n", (gpfsel0_value >> 3) & 0x7);
    printf("  Bits 6-8 (GPIO2): %u\n", (gpfsel0_value >> 6) & 0x7);

    printf("\nRegister Function Values:\n");
    printf("  000 = Input\n");
    printf("  001 = Output\n");
    printf("  100 = Alternate function 0\n");
    printf("  101 = Alternate function 1\n");
    printf("  110 = Alternate function 2\n");
    printf("  111 = Alternate function 3\n");
    printf("  011 = Alternate function 4\n");
    printf("  010 = Alternate function 5\n");

    munmap((void *)gpio_regs, BLOCK_SIZE);
}

/*
 * Main function - display Raspberry Pi hardware information
 */
int main(int argc, char *argv[]) {
    RPiHardwareInfo hw_info;

    printf("=======================================\n");
    printf("   Raspberry Pi Hardware Information\n");
    printf("=======================================\n");

    /* Initialize structure */
    memset(&hw_info, 0, sizeof(RPiHardwareInfo));

    /* Identify the Raspberry Pi model */
    identify_rpi_model(&hw_info);

    /* Get memory information */
    get_memory_info(&hw_info);

    /* Display results */
    printf("\nBoard Information:\n");
    printf("  Model: %s\n", hw_info.model);
    printf("  Revision Code: 0x%04X\n", hw_info.revision);
    printf("  Peripheral Base: 0x%08X\n", hw_info.peripheral_base);
    printf("  Total Memory: %u MB (%.2f GB)\n", 
           hw_info.memory_size / (1024 * 1024),
           (float)hw_info.memory_size / (1024 * 1024 * 1024));

    /* Try to read GPIO registers (requires root) */
    read_gpio_registers(hw_info.peripheral_base);

    printf("\n=======================================\n");
    printf("Note: Run with sudo to access hardware registers\n");
    printf("=======================================\n");

    return 0;
}
